     1→// ============================================================================
     2→// FreeLang Mutex<T> - Mutual Exclusion Lock
     3→// ============================================================================
     4→//
     5→// 여러 스레드가 안전하게 데이터에 접근하도록 배타성을 보장합니다.
     6→//
     7→// 특징:
     8→// - 한 번에 한 스레드만 데이터 접근 가능
     9→// - lock()은 불변 참조로 호출 (내부 가변성)
    10→// - Send: T: Send일 때 소유권 이동 가능
    11→// - Sync: &Mutex<T>를 여러 스레드에서 공유 가능
    12→//
    13→// 작성일: 2026-03-02
    14→// 커밋: Phase B.1 (Week 2)
    15→
    16→use crate::sync::atomic::AtomicBool;
    17→use crate::sync::atomic::Ordering;
    18→use std::ops::{Deref, DerefMut};
    19→
    20→// ============================================================================
    21→// Mutex 구조
    22→// ============================================================================
    23→
    24→/// Mutex<T>: 상호 배제 락
    25→///
    26→/// 내부 가변성(Interior Mutability)을 제공하면서 스레드 안전성을 보장합니다.
    27→pub struct Mutex<T> {
    28→    // 잠금 상태 (true = 잠겨있음, false = 해제됨)
    29→    locked: AtomicBool,
    30→
    31→    // 보호되는 데이터
    32→    data: T,
    33→}
    34→
    35→/// MutexGuard<T>: lock()이 반환하는 RAII 가드
    36→///
    37→/// guard를 drop할 때 자동으로 lock이 해제됩니다.
    38→pub struct MutexGuard<'a, T> {
    39→    // 원본 Mutex에 대한 참조
    40→    mutex: &'a Mutex<T>,
    41→}
    42→
    43→// ============================================================================
    44→// Mutex의 기본 메서드
    45→// ============================================================================
    46→
    47→impl<T> Mutex<T> {
    48→    /// 새로운 Mutex<T>를 생성합니다.
    49→    pub fn new(data: T) -> Mutex<T> {
    50→        Mutex {
    51→            locked: AtomicBool::new(false),
    52→            data,
    53→        }
    54→    }
    55→
    56→    /// 데이터에 대한 배타적 접근을 얻습니다.
    57→    ///
    58→    /// 다른 스레드가 lock을 보유하고 있으면 현재 스레드는 대기합니다.
    59→    /// (이 단순 구현에서는 busy-wait를 사용하고,
    60→    ///  실제로는 futex나 platform mutex을 사용해야 합니다)
    61→    pub fn lock(&self) -> MutexGuard<T> {
    62→        // Busy-wait: 반복해서 lock을 시도
    63→        loop {
    64→            // compare_and_swap: false면 true로 바꾸고 성공했는지 반환
    65→            let was_locked = self.locked.compare_and_swap(
    66→                false,
    67→                true,
    68→                Ordering::SeqCst,
    69→            );
    70→
    71→            if !was_locked {
    72→                // 성공: lock 획득
    73→                return MutexGuard { mutex: self };
    74→            }
    75→
    76→            // 실패: 다시 시도 (yield 또는 sleep)
    77→            std::thread::yield_now();
    78→        }
    79→    }
    80→
    81→    /// Mutex 내부의 데이터를 얻습니다.
    82→    ///
    83→    /// 이 메서드는 &self를 소유하므로, 다른 누구도 접근할 수 없습니다.
    84→    pub fn into_inner(self) -> T {
    85→        self.data
    86→    }
    87→
    88→    /// lock 상태를 반환합니다.
    89→    pub fn is_locked(&self) -> bool {
    90→        self.locked.load(Ordering::SeqCst)
    91→    }
    92→}
    93→
    94→// ============================================================================
    95→// MutexGuard의 Deref 구현
    96→// ============================================================================
    97→
    98→impl<'a, T> Deref for MutexGuard<'a, T> {
    99→    type Target = T;
   100→
   101→    /// guard를 통해 데이터를 불변으로 접근
   102→    fn deref(&self) -> &T {
   103→        &self.mutex.data
   104→    }
   105→}
   106→
   107→impl<'a, T> DerefMut for MutexGuard<'a, T> {
   108→    /// guard를 통해 데이터를 가변으로 접근
   109→    fn deref_mut(&mut self) -> &mut T {
   110→        // SAFETY: guard가 유효한 동안 배타적 접근을 보장
   111→        unsafe {
   112→            &mut *((&self.mutex.data) as *const T as *mut T)
   113→        }
   114→    }
   115→}
   116→
   117→// ============================================================================
   118→// MutexGuard의 Drop 구현
   119→// ============================================================================
   120→
   121→impl<'a, T> Drop for MutexGuard<'a, T> {
   122→    /// guard를 drop할 때 자동으로 lock이 해제됩니다.
   123→    fn drop(&mut self) {
   124→        // lock 해제
   125→        self.mutex.locked.store(false, Ordering::SeqCst);
   126→    }
   127→}
   128→
   129→// ============================================================================
   130→// Send/Sync 구현
   131→// ============================================================================
   132→
   133→// Mutex<T>: Send if T: Send
   134→//
   135→// 설명:
   136→// - Mutex<T>의 소유권을 다른 스레드로 이동할 때,
   137→//   T는 Send여야 합니다.
   138→// - Mutex의 lock은 원자적으로 관리되므로,
   139→//   T: Send만 필요합니다.
   140→impl<T> Send for Mutex<T>
   141→where
   142→    T: Send,
   143→{
   144→}
   145→
   146→// Mutex<T>: Sync
   147→//
   148→// 설명:
   149→// - &Mutex<T>를 여러 스레드에서 공유할 수 있습니다.
   150→// - lock()은 불변 참조로 호출되므로,
   151→//   내부 가변성이 안전하게 구현됩니다.
   152→// - lock() 호출 시 배타성이 보장됩니다.
   153→// - T는 Send여야 합니다 (여러 스레드에서 다른 스레드로
   154→//   데이터가 이동될 수 있으므로).
   155→impl<T> Sync for Mutex<T>
   156→where
   157→    T: Send,
   158→{
   159→}
