   166→mod tests {
   167→    use super::*;
   168→
   169→    #[test]
   170→    fn test_mutex_new() {
   171→        let mutex = Mutex::new(42);
   172→        assert!(!mutex.is_locked());
   173→    }
   174→
   175→    #[test]
   176→    fn test_mutex_lock() {
   177→        let mutex = Mutex::new(vec![1, 2, 3]);
   178→
   179→        {
   180→            let guard = mutex.lock();
   181→            assert!(mutex.is_locked());
   182→            assert_eq!(guard.get_ref(), &vec![1, 2, 3]);
   183→        }
   184→
   185→        // guard가 drop되었으므로 unlock됨
   186→        assert!(!mutex.is_locked());
   187→    }
   188→
   189→    #[test]
   190→    fn test_mutex_deref() {
   191→        let mutex = Mutex::new(10);
   192→
   193→        {
   194→            let guard = mutex.lock();
   195→            assert_eq!(*guard, 10);
   196→        }
   197→    }
   198→
   199→    #[test]
   200→    fn test_mutex_deref_mut() {
   201→        let mutex = Mutex::new(10);
   202→
   203→        {
   204→            let mut guard = mutex.lock();
   205→            *guard = 20;
   206→        }
   207→
   208→        {
   209→            let guard = mutex.lock();
   210→            assert_eq!(*guard, 20);
   211→        }
   212→    }
   213→
   214→    #[test]
   215→    fn test_mutex_drop_unlocks() {
   216→        let mutex = Mutex::new(42);
   217→
   218→        {
   219→            let _guard = mutex.lock();
   220→            assert!(mutex.is_locked());
   221→        }
   222→
   223→        // _guard가 drop되었으므로
   224→        assert!(!mutex.is_locked());
   225→
   226→        // 다시 lock 획득 가능
   227→        let _guard2 = mutex.lock();
   228→        assert!(mutex.is_locked());
   229→    }
   230→
   231→    #[test]
   232→    fn test_mutex_into_inner() {
   233→        let mutex = Mutex::new(String::from("hello"));
   234→        let inner = mutex.into_inner();
   235→        assert_eq!(inner, "hello");
   236→    }
   237→
   238→    #[test]
   239→    fn test_mutex_sequential_access() {
   240→        let mutex = Mutex::new(vec![]);
   241→
   242→        {
   243→            let mut guard = mutex.lock();
   244→            guard.push(1);
   245→            guard.push(2);
   246→        }
   247→
   248→        {
   249→            let guard = mutex.lock();
   250→            assert_eq!(guard.get_ref(), &vec![1, 2]);
   251→        }
   252→    }
   253→
   254→    // 스레드 안전성 테스트 (컴파일 타임)
   255→    #[test]
   256→    fn test_mutex_send_sync() {
   257→        // Mutex<i32>는 Send + Sync
   258→        fn assert_send<T: Send>() {}
   259→        fn assert_sync<T: Sync>() {}
   260→
   261→        assert_send::<Mutex<i32>>();
   262→        assert_sync::<Mutex<i32>>();
   263→    }
   264→
   265→    #[test]
   266→    fn test_mutex_guard_auto_release() {
   267→        let mutex = Mutex::new(0);
   268→
   269→        // Scope 1: lock 획득
   270→        {
   271→            let mut guard = mutex.lock();
   272→            *guard = 1;
   273→            // guard가 scope 벗어나면서 자동 drop → unlock
   274→        }
   275→
   276→        // Scope 2: lock 다시 획득 가능
   277→        {
   278→            let guard = mutex.lock();
   279→            assert_eq!(*guard, 1);
   280→        }
   281→    }
   282→
   283→    #[test]
   284→    fn test_mutex_with_struct() {
   285→        struct Counter {
   286→            value: usize,
   287→        }
   288→
   289→        let mutex = Mutex::new(Counter { value: 0 });
   290→
   291→        {
   292→            let mut guard = mutex.lock();
   293→            guard.value += 1;
   294→        }
   295→
   296→        {
   297→            let guard = mutex.lock();
   298→            assert_eq!(guard.value, 1);
   299→        }
   300→    }
   301→}
