    16→use std::sync::{Arc, Mutex};
    17→use std::thread;
    18→
    19→// ============================================================================
    20→// Job Type
    21→// ============================================================================
    22→
    23→/// 실행할 작업
    24→pub type Job = Box<dyn FnOnce() + Send + 'static>;
    25→
    26→/// 작업 메시지
    27→enum Message {
    28→    NewJob(Job),
    29→    Terminate,
    30→}
    31→
    32→// ============================================================================
    33→// Worker
    34→// ============================================================================
    35→
    36→/// 워커 스레드
    37→struct Worker {
    38→    id: usize,
    39→    thread: Option<thread::JoinHandle<()>>,
    40→}
    41→
    42→impl Worker {
    43→    /// 새로운 워커를 생성합니다.
    44→    fn new(
    45→        id: usize,
    46→        receiver: Arc<Mutex<std::sync::mpsc::Receiver<Message>>>,
    47→    ) -> Worker {
    48→        let thread = thread::spawn(move || {
    49→            loop {
    50→                let message = receiver.lock().unwrap().recv().unwrap();
    51→
    52→                match message {
    53→                    Message::NewJob(job) => {
    54→                        job();
    55→                    }
    56→                    Message::Terminate => {
    57→                        break;
    58→                    }
    59→                }
    60→            }
    61→        });
    62→
    63→        Worker {
